const { greet } = require("./greeting.js");
const { bound } = require("./bound.js");
function run(argv) {
  let name = "";
  let score = 0;
  for (let i = 0; i < argv.length; i++) {
    if (argv[i] === "--name") name = argv[++i];
    else if (argv[i] === "--score") score = Number(argv[++i]);
  }
  return `${greet(name).title} scored ${bound(score)}`;
}
module.exports = { run };
